INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '53290f00-673a-4054-b896-632acdd61554',
  '00000000-0000-0000-0000-000000000001',
  $escape$PHP Performance Profiling — hrtime(), OPcache, and Xdebug's Overhead Cost$escape$,
  $escape$PHP's `hrtime(true)` returns nanoseconds via the CPU clock — far more precise than `microtime(true)` for micro-benchmarks, since it's immune to NTP drift. Use it to wrap candidate code paths: `$start = hrtime(true); ... $ns = hrtime(true) - $start;`. But raw timing means nothing without OPcache context. On first request, PHP parses and compiles every file; OPcache serializes the opcode bytecode to shared memory, making subsequent requests up to 5–8× faster. Benchmark only after OPcache warms up — `opcache_get_status()` confirms it. For deep profiling, Xdebug's profiler (`xdebug.mode=profile`) emits Cachegrind files readable by KCacheGrind, but introduces 10–100× slowdown — never run it in production. Instead, use Blackfire.io, which instruments via a PHP extension with ~2% overhead and gives call graph analysis per function. Key runtime gotcha: PHP is share-nothing per request — no persistent in-process state, so memory leaks are per-request and reset automatically, but connection pool warm-up costs hit every worker process independently.$escape$,
  $escape$<?php
// Warm OPcache before benchmarking
$status = opcache_get_status();
if (!$status || !$status['opcache_enabled']) {
    throw new RuntimeException('OPcache must be enabled for reliable benchmarks');
}

$iterations = 10_000;
$start = hrtime(true);

for ($i = 0; $i < $iterations; $i++) {
    $result = array_map(fn($x) => $x * $x, range(1, 100));
}

$ns = hrtime(true) - $start;
printf("avg: %.3f µs/iter\n", $ns / $iterations / 1_000);$escape$,
  $escape$php$escape$,
