INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '533aa19d-0a7b-40bc-984a-61d50221ccf4',
  '00000000-0000-0000-0000-000000000001',
  $escape$PHP Security — Injection Prevention, Memory Safety, and Dependency Scanning$escape$,
  $escape$PHP's biggest injection risks are SQL and shell execution. Use PDO with named prepared statements exclusively — never interpolate user input into queries. For shell calls, avoid `exec()`, `shell_exec()`, and `passthru()` entirely; if unavoidable, use `escapeshellarg()` on every argument. PHP 8.x doesn't offer Rust-style memory safety, but you eliminate entire classes of buffer-adjacent bugs by disabling `allow_url_fopen`, `allow_url_include`, and `register_globals` in `php.ini`. Unserializing untrusted data via `unserialize()` is a critical RCE vector — use `json_decode()` instead, or pass an `allowed_classes` whitelist as the second argument. For dependency scanning, integrate `composer audit` into your CI pipeline; it queries the OSS vulnerability database against your `composer.lock` and exits non-zero on known CVEs, blocking merges automatically. Pair with `roave/security-advisories` as a Composer dev-dependency — it prevents installation of packages with known security issues at `composer install` time, before your code ever runs.$escape$,
  $escape$<?php
// Safe PDO query — named placeholders, no interpolation
$stmt = $pdo->prepare('SELECT * FROM users WHERE email = :email AND active = :active');
$stmt->execute([':email' => $email, ':active' => 1]);

// Safe unserialize with class allowlist
$data = unserialize($input, ['allowed_classes' => [UserPrefs::class]]);

// Safe shell argument — never trust user input directly
$file = escapeshellarg($_GET['filename']);
exec("convert {$file} output.png");

// CI: run in your GitHub Actions pipeline
// composer audit --no-dev --format=json$escape$,
  $escape$bash$escape$,
