INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '341be734-bc29-4296-ad42-3a132f1857fc',
  '00000000-0000-0000-0000-000000000001',
  $escape$PHP Standard Library — What's Built In vs What You Actually Need Composer For$escape$,
  $escape$PHP ships with a surprisingly deep standard library, but knowing its gaps saves you from reinventing wheels or pulling in unnecessary dependencies. Built-in and ready: `PDO` for database access, `cURL` via ext-curl, `json_encode`/`json_decode`, `DateTime`/`DateTimeImmutable`, `SPL` data structures (`SplStack`, `SplMinHeap`), `array_map`/`array_filter`/`array_reduce`, `preg_*` for regex, `hash()`/`password_hash()` for crypto, and `intl` for Unicode-aware string ops. Where PHP's stdlib falls short: structured logging (reach for `monolog/monolog`), dependency injection containers (`php-di/php-di` or `symfony/dependency-injection`), robust HTTP clients (`guzzlehttp/guzzle` or `symfony/http-client`), UUID generation (`ramsey/uuid`), and any real ORM (`doctrine/orm` or `eloquent`). PHP also lacks a built-in async runtime — for non-blocking I/O you need `ReactPHP` or `Swoole`. Rule of thumb: if it touches I/O, formatting, or application architecture beyond basic CRUD, Composer is the right answer. The stdlib covers primitives; the ecosystem covers patterns.$escape$,
  $escape$<?php
// Built-in: hashing, JSON, DateTimeImmutable — no Composer needed
$hash = password_hash('secret', PASSWORD_ARGON2ID);
$payload = json_encode(['ts' => (new DateTimeImmutable())->getTimestamp()]);

// Built-in: PDO for DB access
$pdo = new PDO('pgsql:host=localhost;dbname=app', 'user', 'pass');
$stmt = $pdo->prepare('SELECT * FROM users WHERE id = ?');
$stmt->execute([42]);

// Third-party needed: structured logging
// composer require monolog/monolog
use Monolog\Logger;
use Monolog\Handler\StreamHandler;
$log = new Logger('app');
$log->pushHandler(new StreamHandler('php://stdout'));
$log->info('User fetched', ['id' => 42]);$escape$,
  $escape$php$escape$,
