INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e478b3a4-d65d-4ccd-9f94-7eb306c81a80',
  '00000000-0000-0000-0000-000000000001',
  $escape$PHP Dev Tooling — REPL, Xdebug, and LSP in Your Editor$escape$,
  $escape$PHP's `psysh` is the de facto REPL for interactive debugging and prototyping. Drop it into any project with `composer require --dev psy/psysh` and launch with `vendor/bin/psysh`. Inside, you get `ls()` to inspect object properties, `doc()` for inline PHPDoc, and `wtf` to pretty-print the last exception — far more useful than `php -a`.

For step debugging, Xdebug 3 streamlines configuration: set `xdebug.mode=debug` and `xdebug.start_with_request=yes` in your `php.ini`, then attach VS Code via the PHP Debug extension (felixfbecker.php-debug). Conditional breakpoints and stack inspection work out of the box.

Language server support comes from `phpactor` or `intelephense`. Phpactor is open-source and installable as a PHAR; it provides go-to-definition, refactoring, and class import resolution via LSP. Configure it in Neovim with `nvim-lspconfig` using the `phpactor` server entry, or in VS Code as a standalone extension. Intelephense's free tier covers most LSP features with better performance on large codebases.$escape$,
  $escape$# Install PsySH
composer require --dev psy/psysh

# Launch REPL
vendor/bin/psysh

# php.ini — Xdebug 3 config
; xdebug.mode=debug
; xdebug.start_with_request=yes
; xdebug.client_host=127.0.0.1
; xdebug.client_port=9003

# Install Phpactor LSP
wget https://github.com/phpactor/phpactor/releases/latest/download/phpactor.phar
chmod +x phpactor.phar && mv phpactor.phar /usr/local/bin/phpactor
phpactor status$escape$,
  $escape$bash$escape$,
