INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4ea43074-092f-44fb-9da3-913d895f98b6',
  '00000000-0000-0000-0000-000000000001',
  $escape$PHP in Docker — Slim Images, OPcache, and No-Dev Deploys$escape$,
  $escape$PHP's runtime model makes container size surprisingly controllable. Start with `php:8.3-fpm-alpine` (~30MB base) instead of the default Debian variant (~170MB). Use a multi-stage build: a `composer` stage installs dependencies with `--no-dev --optimize-autoloader --classmap-authoritative`, then the final stage copies only `vendor/` and app code — no Composer binary ships to prod. Strip unused extensions; every `docker-php-ext-install` call adds shared objects to the image. For runtime performance, bake OPcache config directly into the image via a custom `php.ini`: set `opcache.validate_timestamps=0` and `opcache.preload` pointing to your preload script. This eliminates per-request file-stat syscalls entirely. Avoid mounting `php.ini` at runtime — it creates environment drift. Pin your PHP version in `FROM` (never `php:fpm-latest`) and lock Composer deps with `composer.lock` committed to git. The result: a deterministic, ~80MB image with no dev tooling, no stray `.so` files, and preloaded bytecode ready on first request.$escape$,
  $escape$# Stage 1: install deps
FROM composer:2.7 AS deps
WORKDIR /app
COPY composer.json composer.lock ./
RUN composer install --no-dev --optimize-autoloader --classmap-authoritative

# Stage 2: runtime
FROM php:8.3-fpm-alpine
COPY --from=deps /app/vendor ./vendor
COPY . .
COPY docker/php.ini /usr/local/etc/php/conf.d/production.ini
# php.ini includes: opcache.enable=1, opcache.validate_timestamps=0
EXPOSE 9000
CMD ["php-fpm"]$escape$,
  $escape$bash$escape$,
