INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f9859ffd-12a3-474d-b1b1-817cb0c7d3eb',
  '00000000-0000-0000-0000-000000000001',
  $escape$PHP Code Quality — PHP_CodeSniffer, PHP-CS-Fixer, and PHPStan in Practice$escape$,
  $escape$PHP has a mature toolchain for enforcing code quality, but teams often pick one tool and miss the others. PHP_CodeSniffer (`phpcs`) enforces coding standards like PSR-12 — it catches missing type declarations, incorrect brace placement, and unused imports. PHP-CS-Fixer goes further by auto-correcting violations rather than just reporting them; run it with `--rules=@PSR12,@PHP81Migration` to modernize codebases in bulk. PHPStan is the static analysis layer — at level 8, it catches type mismatches, dead code, and impossible conditions before runtime.

Beyond formatting, embrace PHP 8.x idioms: use `match` instead of `switch` to enforce exhaustive matching and avoid fall-through bugs; replace `isset($arr['key']) ? $arr['key'] : 'default'` with `$arr['key'] ?? 'default'`; and prefer named arguments when calling functions with ambiguous boolean params. Wire all three tools into your CI pipeline using a single `composer run lint` script so there's no escape hatch. PHPStan and PHP-CS-Fixer together eliminate entire categories of review comments.$escape$,
  $escape$// composer.json scripts block
"scripts": {
    "lint": [
        "phpcs --standard=PSR12 src/",
        "php-cs-fixer fix --dry-run --diff --rules=@PSR12,@PHP81Migration src/",
        "phpstan analyse src/ --level=8"
    ],
    "fix": "php-cs-fixer fix --rules=@PSR12,@PHP81Migration src/"
}

// PHPStan config: phpstan.neon
parameters:
    level: 8
    paths:
        - src
    checkMissingIterableValueType: true$escape$,
  $escape$bash$escape$,
